import type { SearchInputConfig } from '@linm-soft/common-components';
import { masterService } from '../../services/master/masterService';
import type { CustomerDto } from '../../services/master/models';

export type CustomerSearchType = 'Customer' | 'Supplier' | 'Both';

export interface CreateCustomerSearchConfigOptions {
  customerType?: CustomerSearchType;
}

/** SEARCH_REMOTE — `GET /master/customers` (customerType=Customer for sales). */
export function createCustomerSearchConfig(
  options: CreateCustomerSearchConfigOptions = {},
): SearchInputConfig<CustomerDto> {
  const { customerType = 'Customer' } = options;

  return {
    api: {
      getItemKey: c => c.customerId,
      search: async ({ search, page, pageSize }) => {
        const res = await masterService.searchCustomers({
          search: search?.trim() || undefined,
          page,
          pageSize,
          customerType,
          isActive: true,
        });
        const totalPages = Math.max(1, Math.ceil(res.totalCount / pageSize));
        return { items: res.items, page: res.page, totalPages };
      },
      getDetail: id => masterService.getCustomer(id),
    },
    display: {
      getPrimaryDisplay: c => c.code,
      getSecondaryDisplay: c => c.name,
      getSingleDisplay: c => c.name,
    },
    columns: [
      { key: 'code', variant: 'badge', width: '5rem', render: c => c.code },
      { key: 'name', variant: 'primary', width: 'minmax(0, 1fr)', render: c => c.name },
      {
        key: 'phone',
        variant: 'meta',
        width: '7rem',
        align: 'end',
        icon: 'fas fa-phone',
        visible: c => !!c.phone,
        render: c => c.phone ?? '',
      },
    ],
    header: {
      columns: [
        { key: 'code', label: 'Mã' },
        { key: 'name', label: 'Tên khách hàng' },
        { key: 'phone', label: 'Điện thoại' },
      ],
    },
    texts: {
      secondaryPlaceholder: 'Tên khách hàng',
      empty: 'Không tìm thấy khách hàng',
    },
    dropdownPortal: true,
    dropdownMatch: 'lookup',
    dropdownMaxWidth: 'min(720px, calc(100vw - 32px))',
  };
}
